head.script:
//-------------------------------------------------------------------------
// 화면 로딩
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	scwin.oldValue;
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_fieldClear = function() {
	console.log("scwin.f_fieldClear");
	$c.gus.cfInitObjects(tbl_search);
    ds_echVhclClntList.removeAll();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function() {
    let chkVal = await $c.gus.cfValidate([tbl_search]);
    if(!chkVal) return;

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------  
scwin.f_save = function() {
    if(!$c.data.isModified(ds_echVhclClntList)) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    $c.sbm.execute(sbm_save);
}

//-------------------------------------------------------------------------
// 공통 팝업 호출
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, rowIndex) {
  	var pWhere;		// 조회조건

	switch (disGubun) {
  		case 1:   //  거래처조회 - 그리드				
			pWhere = "01";
			pCode = ds_echVhclClntList.getCellData(rowIndex, "clntNo").replace(/\s*$/, '');
    		pName = ds_echVhclClntList.getCellData(rowIndex, "clntNo");

  			udc_comCode.cfCommonPopUp(   scwin.callBackCarKind
                                        ,pCode					
                                        ,pName					
                                        ,pClose					
                                        ,null					
                                        ,null					
                                        ,null					
                                        ,"3,4,5,6,7,8,9,10"		
                                        ,null					
                                        ,null					
                                        ,null					
                                        ,null					
                                        ,null					
                                        ,null					
                                        ,pAllSearch					
                                        ,"거래처조회,거래처코드,거래처명"
                                        ,null  									
                                        );            
			break;

		case 2:   //  거래처조회	- 조회조건			
			pWhere = "";

  			udc_opentopblcMgntCo.cfCommonPopUp( scwin.callBackBpClnt
                                                ,pCode				
                                                ,pName				
                                                ,pClose				
                                                ,null				
                                                ,null				
                                                ,null				
                                                ,"3,4,5,6,7,8,9,10"	
                                                ,pWhere				
                                                ,null			
                                                ,null			
                                                ,null			
                                                ,null			
                                                ,null			
                                                ,pAllSearch		
                                                ,"거래처조회,거래처코드,거래처명"			
                                                ,null  									
                                                );
			break;
  	}
}

//-------------------------------------------------------------------------
// 공통코드 조회 callBack
//-------------------------------------------------------------------------
//  거래처조회 - 그리드
scwin.callBackCarKind = function(rtnList) {
    if(rtnList != null) {
        if(rtnList[0].trim()!= "N/A") {	
            ds_echVhclClntList.setCellData(ds_echVhclClntList.getRowPosition(), "clntNo", rtnList[0]);                                                                                                                                                                                                                                                                
            ds_echVhclClntList.setCellData(ds_echVhclClntList.getRowPosition(), "clntNm", rtnList[1]); 
        }
    }
}

//  거래처조회	- 조회조건
scwin.callBackBpClnt = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_opentopblcMgntCo, ed_opentopblcMgntCoNm);
}

//-------------------------------------------------------------------------
// 거래처조회
//------------------------------------------------------------------------- 
scwin.f_registClnt = function() {
    var opts = {
          id : "tn_101_01_06b"
        , popupName : "거래처등록"
        , modal : true
        , type : "browserPopup" 
        , title : "거래처등록"  
        , width : 1100
        , height : 750
    };

    $c.win.openPopup("/ui/tn/cs/clntmgnt/tn_101_01_06b.xml", opts);
}

/* ----------------------------------------------------------------------------
  T R A N S A C T I O N   C O M P O N E N T S   D E C L A R A T I O N
------------------------------------------------------------------------------*/
//조회 완료
scwin.sbm_retrieve_submitdone = function(e) {
    console.log("scwin.sbm_retrieve_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    var rowCnt = ds_echVhclClntList.getTotalRow();
	spn_totalRow.setValue(rowCnt);

    if(rowCnt == 0) {
	    $c.win.alert("차량정보가 존재하지 않습니다.");
	} else {
        gr_echVhclClntList.setFocusedCell(0, 0);
    }
};

//저장 완료
scwin.sbm_save_submitdone = function (e) {
    console.log("scwin.sbm_save_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    $c.gus.cfAlertMsg(MSG_CM_INF_001);
	scwin.f_retrieve();
};

/* ----------------------------------------------------------------------------
  C O M P O N E N T' S   E V E N T S  
-----------------------------------------------------------------------------*/
//소속거래처 찾기 버튼
scwin.udc_opentopblcMgntCo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_opentopblcMgntCo.getValue(), ed_opentopblcMgntCoNm.getValue(), 'F', 'F');
};

scwin.udc_opentopblcMgntCo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_opentopblcMgntCo, ed_opentopblcMgntCoNm, 2);
};

//조회조건 clear 버튼
scwin.btn_clear_onclick = function (e) {
    console.log("scwin.btn_clear_onclick");
    scwin.f_fieldClear();
};

//조회 버튼
scwin.btn_search_onclick = function (e) {
    console.log("scwin.btn_search_onclick");
    scwin.f_retrieve(); 
};

//거래처등록 버튼
scwin.btn_regist_onclick = function (e) {
    scwin.f_registClnt();
};

//저장 버튼
scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

//그리드 정산거래처 코드 클릭 > 공통 팝업 호출
scwin.gr_echVhclClntList_onviewchange = function (info) {
    debugger;
    let rowIndex = ds_echVhclClntList.getRowPosition();
    if(!$c.util.isEmpty(ds_echVhclClntList.getOriginalCellData(rowIndex, gr_echVhclClntList.getFocusedColumnID()))){
        $c.win.alert("이미 등록된 거래처가 있습니다.");
        ds_echVhclClntList.undoRow(rowIndex);
    } else {
        if(scwin.pWinCloseTF != "F" && info.newValue == "") return;
        let pWinCloseTF = $c.util.isEmpty(scwin.pWinCloseTF)? "T" : "F"
        scwin.f_openCommonPopUp(1, null, null, pWinCloseTF, 'F', rowIndex);
    }
    scwin.pWinCloseTF = "";
};

scwin.gr_echVhclClntList_ontextimageclick = function (rowIndex, columnIndex) {
    if($c.util.isEmpty(gr_echVhclClntList.getCellDisplayData(rowIndex, columnIndex))) {
        scwin.pWinCloseTF = "F";
        scwin.gr_echVhclClntList_onviewchange();
    }
};
